function solve(nums) {
    const n = nums.length;

    // Step 1: Find the peak index p
    // The peak is the last element that is strictly smaller than its successor, 
    // or the last element if the array is strictly increasing up to the end.
    let p = 0;
    while (p + 1 < n && nums[p] < nums[p + 1]) {
        p++;
    }

    // Step 2: Calculate sums

    // Sum of the increasing part: indices 0 to p
    let sumInc = 0;
    for (let i = 0; i <= p; i++) {
        sumInc += nums[i];
    }

    // Sum of the decreasing part: indices p to n-1
    let sumDec = 0;
    for (let i = p; i < n; i++) {
        sumDec += nums[i];
    }

    // Step 3: Comparison
    if (sumInc > sumDec) {
        return 0; // Increasing part sum is larger
    } else if (sumDec > sumInc) {
        return 1; // Decreasing part sum is larger
    } else {
        return -1; // Sums are equal
    }
}

